Create apps/frontend/lib/governance.ts. Implement generateContentHash(title: string, description: string): string function using ethers.js v6:

import { keccak256, toUtf8Bytes } from 'ethers';

export function generateContentHash(title: string, description: string): string {
  const content = `${title}|||${description}`; // Use separator to prevent collision
  const contentBytes = toUtf8Bytes(content);
  return keccak256(contentBytes); // Returns 0x-prefixed hex string
}

export function verifyContentHash(title: string, description: string, hash: string): boolean {
  return generateContentHash(title, description) === hash;
}

