Implementation:

export const GET = withAuth(async (req: NextRequest, user, _session, { params }: RouteParams): Promise<NextResponse> => {
  try {
    const { id: proposalId } = await params;

    // Validate proposal exists
    const proposal = await prisma.proposal.findUnique({ 
      where: { id: proposalId },
      include: {
        _count: {
          select: {
            votes: true
          }
        },
        votes: {
          where: { vote: 'UPVOTE' }
        }
      }
    });

    if (!proposal) {
      return NextResponse.json({ error: 'Proposal not found' }, { status: 404 });
    }

    // Check if proposal has been deployed on-chain
    const votingActive = proposal.onChainId !== null && 
                        proposal.onChainStatus === 'ACTIVE' &&
                        proposal.votingEndsAt !== null &&
                        new Date() < proposal.votingEndsAt;

    // Get user's current vote if exists
    const userVote = await prisma.proposalVote.findUnique({
      where: { 
        proposalId_userId: { 
          proposalId, 
          userId: user.id 
        }
      }
    });

    // Calculate vote counts
    const upvoteCount = proposal.votes.length;
    const totalVotes = proposal._count.votes;
    const downvoteCount = totalVotes - upvoteCount;

    return NextResponse.json({
      contractAddress: process.env.NEXT_PUBLIC_GOVERNANCE_CONTRACT_ADDRESS,
      chainId: Number(process.env.NEXT_PUBLIC_CHAIN_ID || 11155111), // Default to Sepolia
      onChainId: proposal.onChainId,
      votingActive,
      votingEndsAt: proposal.votingEndsAt?.toISOString() || null,
      onChainStatus: proposal.onChainStatus,
      userVote: userVote ? userVote.vote : null,
      voteCounts: {
        upvotes: upvoteCount,
        downvotes: downvoteCount,
        total: totalVotes
      },
      estimatedGas: {
        vote: "100000", // Estimated gas for contract.vote() call
        gasPrice: null // Frontend will fetch current gas price
      }
    });
  } catch (error) {
    console.error('Failed to fetch vote info:', error);
    return NextResponse.json(
      { error: 'Failed to fetch vote info' },
      { status: 500 }
    );
  }
});

