Create apps/frontend/lib/governance/finalization.ts. This utility checks finalization eligibility by reading vote data directly from the W3Governance smart contract on Sepolia.

Implement checkFinalizationEligibility(proposalId: number): Promise<FinalizationEligibility>

interface FinalizationEligibility {
  proposalId: number;
  canFinalize: boolean;
  votingEnded: boolean;
  alreadyFinalized: boolean;
  upvoteCount: bigint;
  downvoteCount: bigint;
  totalVotes: bigint;
  passThresholdMet: boolean; // 2/3 majority (upvotes >= totalVotes * 2/3)
  votingEndsAt: bigint; // Unix timestamp from contract
  currentTime: bigint; // Current Unix timestamp
  reason?: string; // If canFinalize is false, explain why
}

async function checkFinalizationEligibility(proposalId: number): Promise<FinalizationEligibility> {
  // 1. Create contract instance (follow pattern from packages/common/contract.ts)
  //    Use packages/common/governance-contract.ts (to be created in Task 5)
  //    Connect to Sepolia RPC provider (no signer needed for read-only)

  // 2. Call contract.getProposal(proposalId) to retrieve on-chain data
  //    Returns OnChainProposal (defined in Task 2: packages/common/governance-types.ts)
  //    OnChainProposal has: id, proposer, contentHash, createdAt, votingEndsAt,
  //                         upvotes, downvotes, finalized, passed

  // 3. Get current block timestamp:
  //    const block = await provider.getBlock('latest');
  //    const currentTime = BigInt(block.timestamp);

  // 4. Calculate eligibility:
  const votingEnded = currentTime >= proposal.votingEndsAt;
  const alreadyFinalized = proposal.finalized;
  const totalVotes = proposal.upvotes + proposal.downvotes;
  const passThresholdMet = proposal.upvotes >= (totalVotes * BigInt(2) / BigInt(3));

  // 5. Determine canFinalize and reason:
  let canFinalize = false;
  let reason: string | undefined;

  if (alreadyFinalized) {
    reason = 'Proposal already finalized';
  } else if (!votingEnded) {
    const timeRemaining = proposal.votingEndsAt - currentTime;
    reason = `Voting period ends in ${timeRemaining} seconds`;
  } else if (totalVotes === BigInt(0)) {
    reason = 'No votes cast';
  } else {
    canFinalize = true;
  }

  return {
    proposalId,
    canFinalize,
    votingEnded,
    alreadyFinalized,
    upvoteCount: proposal.upvotes,
    downvoteCount: proposal.downvotes,
    totalVotes,
    passThresholdMet,
    votingEndsAt: proposal.votingEndsAt,
    currentTime,
    reason
  };
}

Add helper functions:
- formatTimeRemaining(seconds: bigint): string - converts seconds to human-readable format ("2 hours", "5 minutes")
- calculatePassPercentage(upvotes: bigint, totalVotes: bigint): number - returns percentage (0-100)

