async start() {
  // Existing ProposalCreated listener...

  this.contract.on('ProposalFinalized', async (proposalId, upvotes, downvotes, passed, event) => {
    await this.handleProposalFinalized(proposalId, upvotes, downvotes, passed, event);
  });
}

private async handleProposalFinalized(proposalId: bigint, upvotes: bigint, downvotes: bigint, passed: boolean, event: Log) {
  // Find proposal by onChainId
  const proposal = await prisma.proposal.findUnique({
    where: { onChainId: Number(proposalId) }
  });

  if (!proposal) {
    console.error(`Proposal with onChainId ${proposalId} not found`);
    return;
  }

  // Update with finalization data
  await prisma.proposal.update({
    where: { id: proposal.id },
    data: {
      finalizationTxHash: event.transactionHash,
      onChainStatus: passed ? 'PASSED' : 'FAILED',
      status: passed ? 'APPROVED' : 'REJECTED',
      updatedAt: new Date()
    }
  });

  console.log(`Proposal ${proposal.id} finalized on-chain: ${passed ? 'PASSED' : 'FAILED'}`);
}

Handle edge cases: proposal not found, duplicate events (idempotent updates), transaction hash extraction. Note: No need to update vote cache as votes are already on-chain and synced via VoteCast listener.

