export const GET = async (req: NextRequest) => {
  const { searchParams } = new URL(req.url);
  const includeOffChain = searchParams.get('includeOffChain') === 'true';

  // Query proposals with on-chain data
  const where = includeOffChain ? {} : { onChainStatus: { not: 'DRAFT' }};

  const proposals = await prisma.proposal.findMany({
    where,
    include: {
      user: { select: { walletAddress: true }},
      votes: true // Legacy off-chain votes for comparison
    },
    orderBy: { createdAt: 'desc' }
  });

  // Transform to dashboard format
  const dashboardData = await Promise.all(proposals.map(async p => {
    // For on-chain proposals, fetch vote counts from contract
    let onChainVotes = { upvotes: 0, downvotes: 0, total: 0 };
    if (p.onChainId) {
      try {
        const provider = new AlchemyProvider('sepolia', process.env.ALCHEMY_API_KEY);
        const contract = createGovernanceContract(provider);
        const onChainProposal = await contract.getProposal(p.onChainId);
        onChainVotes = {
          upvotes: Number(onChainProposal.upvotes),
          downvotes: Number(onChainProposal.downvotes),
          total: Number(onChainProposal.upvotes) + Number(onChainProposal.downvotes)
        };
      } catch (error) {
        console.error(`Failed to fetch on-chain votes for proposal ${p.onChainId}:`, error);
      }
    }

    return {
      id: p.id,
      title: p.title,
      type: p.type,
      status: p.status,
      onChainStatus: p.onChainStatus,
      proposer: p.user.walletAddress,
      createdAt: p.createdAt,

      // On-chain verification
      onChainId: p.onChainId,
      contentHash: p.contentHash,
      creationTxHash: p.creationTxHash,
      creationTxUrl: p.creationTxHash ? `https://sepolia.etherscan.io/tx/${p.creationTxHash}` : null,
      finalizationTxHash: p.finalizationTxHash,
      finalizationTxUrl: p.finalizationTxHash ? `https://sepolia.etherscan.io/tx/${p.finalizationTxHash}` : null,

      // Voting data
      votingEndsAt: p.votingEndsAt,
      onChainVotes,
      legacyVotes: {
        upvotes: p.votes.filter(v => v.vote === 'UPVOTE').length,
        downvotes: p.votes.filter(v => v.vote === 'DOWNVOTE').length
      }
    };
  }));

  // Calculate platform statistics
  const stats = {
    totalProposals: proposals.length,
    onChainProposals: proposals.filter(p => p.onChainId !== null).length,
    finalizedProposals: proposals.filter(p => p.onChainStatus === 'PASSED' || p.onChainStatus === 'FAILED').length,
    activeVoting: proposals.filter(p => p.onChainStatus === 'ACTIVE' && new Date() < p.votingEndsAt!).length
  };

  return NextResponse.json({ proposals: dashboardData, stats });
};

