Create apps/frontend/hooks/useGovernanceContract.ts:

import { useState, useEffect } from 'react';
import { Contract, BrowserProvider } from 'ethers';
import { createGovernanceContract } from 'common/governance-contract';

export function useGovernanceContract() {
  const [contract, setContract] = useState<Contract | null>(null);
  const [provider, setProvider] = useState<BrowserProvider | null>(null);
  const [isConnected, setIsConnected] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const initContract = async () => {
      try {
        if (typeof window === 'undefined' || !window.ethereum) {
          setError('MetaMask not installed');
          return;
        }

        const browserProvider = new BrowserProvider(window.ethereum);
        const network = await browserProvider.getNetwork();

        if (network.chainId !== 11155111n) {
          setError('Please switch to Sepolia network');
          return;
        }

        const contractInstance = createGovernanceContract(browserProvider);
        setContract(contractInstance);
        setProvider(browserProvider);
        setIsConnected(true);
        setError(null);
      } catch (err) {
        setError(err instanceof Error ? err.message : 'Failed to initialize contract');
      }
    };

    initContract();

    // Listen for network changes
    if (window.ethereum) {
      window.ethereum.on('chainChanged', () => {
        initContract();
      });
    }

    return () => {
      if (window.ethereum) {
        window.ethereum.removeAllListeners('chainChanged');
      }
    };
  }, []);

  const createProposal = async (contentHash: string, votingDuration: number = 7 * 24 * 60 * 60) => {
    if (!contract || !provider) throw new Error('Contract not initialized');

    const signer = await provider.getSigner();
    const contractWithSigner = contract.connect(signer);

    const tx = await contractWithSigner.createProposal(contentHash, votingDuration);
    const receipt = await tx.wait();

    // Parse ProposalCreated event
    const event = receipt.logs.find(log => {
      try {
        return contract.interface.parseLog(log)?.name === 'ProposalCreated';
      } catch { return false; }
    });

    if (!event) throw new Error('ProposalCreated event not found');
    const parsed = contract.interface.parseLog(event)!;

    return {
      proposalId: Number(parsed.args.proposalId),
      txHash: receipt.hash,
      blockNumber: receipt.blockNumber
    };
  };

  const vote = async (proposalId: number, support: boolean) => {
    if (!contract || !provider) throw new Error('Contract not initialized');

    const signer = await provider.getSigner();
    const contractWithSigner = contract.connect(signer);

    const tx = await contractWithSigner.vote(proposalId, support);
    const receipt = await tx.wait();

    return {
      txHash: receipt.hash,
      blockNumber: receipt.blockNumber
    };
  };

  const getProposal = async (proposalId: number) => {
    if (!contract) throw new Error('Contract not initialized');
    return await contract.getProposal(proposalId);
  };

  const getVote = async (proposalId: number, voter: string) => {
    if (!contract) throw new Error('Contract not initialized');
    return await contract.getVote(proposalId, voter);
  };

  return {
    contract,
    provider,
    isConnected,
    error,
    createProposal,
    vote,
    getProposal,
    getVote
  };
}

