    address indexed user,
    uint256 amount,
    uint256 nonce,
    uint256 timestamp
);

event PlatformSignerUpdated(
    address indexed oldSigner,
    address indexed newSigner,
    uint256 timestamp
);
```

**Add Custom Errors:**
```solidity
