    emit ReputationDeducted(
        msg.sender,
        PROPOSAL_REPUTATION_COST,
        "createProposal",
        block.timestamp
    );

    emit ProposalCreated(proposalId, msg.sender, contentHash, block.timestamp + votingDuration);
