function vote(uint256 proposalId, bool support) external {
    Proposal storage proposal = proposals[proposalId];

    // Existing validations
    require(proposal.votingEndsAt > 0, "Proposal does not exist");
    require(block.timestamp < proposal.votingEndsAt, "Voting period ended");

    // NEW: Nonce-based duplicate check (O(1) gas cost)
    require(voteNonces[proposalId][msg.sender] == 0, "Already voted on this proposal");

    // Check reputation balance (from Task 35)
    require(reputationBalance[msg.sender] >= VOTE_REPUTATION_COST, "Insufficient reputation");

    // Deduct reputation
