**Error Handling:**

Follow useExecuteWithdrawal error patterns (apps/frontend/hooks/useWithdrawalExecution.ts:74-104):

```typescript
catch (error: unknown) {
  const errorObj = error as { code?: number; message?: string };
  const errorMessage = errorObj.message || '';

  // User rejection
  if (errorObj.code === 4001) {
    throw new Error('Transaction rejected by user');
  }

  // Contract-specific errors
  if (errorMessage.includes('InsufficientClaimableAmount')) {
    throw new Error('No reputation available to claim');
  }
  if (errorMessage.includes('InvalidSignature')) {
    throw new Error('Invalid claim signature - please try again');
  }
  if (errorMessage.includes('SignatureExpired')) {
    throw new Error('Claim signature expired - please refresh and try again');
  }
  if (errorMessage.includes('AlreadyClaimed')) {
    throw new Error('This reputation has already been claimed');
  }

  // Gas errors
  if (errorMessage.includes('insufficient funds')) {
    throw new Error('Insufficient ETH for gas fees');
  }
  if (errorMessage.includes('gas required exceeds allowance')) {
    throw new Error('Transaction would fail - insufficient gas');
  }

  // Fallback
  if (error instanceof Error) throw error;
  throw new Error('Unknown error occurred during claim');
}
```

