interface ReputationClaimModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  availableReputation: string; // Wei amount as string
  userAddress: string;
}

export function ReputationClaimModal({
  open,
  onOpenChange,
  availableReputation,
  userAddress
}: ReputationClaimModalProps) {
  const [currentStep, setCurrentStep] = useState<string>('');
  const [transactionHash, setTransactionHash] = useState<string | null>(null);
  const [estimatedGas, setEstimatedGas] = useState<string | null>(null);

  const claimMutation = useClaimReputation();

  // Calculate human-readable reputation amount
  const reputationPoints = ethers.formatEther(availableReputation);
  const hasReputation = parseFloat(reputationPoints) > 0;

  // Estimate gas cost on modal open
  useState(() => {
    if (open && hasReputation) {
      estimateGasCost();
    }
  }, [open, hasReputation]);

  const estimateGasCost = async () => {
    try {
      if (!window.ethereum) return;
      const provider = new ethers.BrowserProvider(window.ethereum);
      const gasPrice = await provider.getFeeData();
      // Estimate ~100,000 gas for claim transaction
      const estimatedCost = BigInt(100000) * (gasPrice.gasPrice || BigInt(0));
      setEstimatedGas(ethers.formatEther(estimatedCost));
    } catch (error) {
      console.error('Gas estimation failed:', error);
    }
  };

  const handleClaim = async () => {
    try {
      const result = await claimMutation.mutateAsync({
        onProgress: (step: string) => setCurrentStep(step)
      });
      setTransactionHash(result.transactionHash);
    } catch (error) {
      console.error('Claim failed:', error);
    }
  };

  const handleClose = () => {
    if (!claimMutation.isPending) {
      onOpenChange(false);
      // Reset state after close animation
      setTimeout(() => {
        setTransactionHash(null);
        setCurrentStep('');
        claimMutation.reset();
      }, 300);
    }
  };

  return (
    <Dialog open={open} onOpenChange={handleClose}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle>Claim Reputation Rewards</DialogTitle>
          <DialogDescription>
