              <span className="text-2xl font-bold">{reputationPoints} REP</span>
            </div>
            {estimatedGas && (
              <div className="flex justify-between items-center text-sm">
                <span className="text-muted-foreground">Estimated Gas Cost</span>
                <span className="font-mono">{parseFloat(estimatedGas).toFixed(6)} SEP</span>
              </div>
            )}
          </div>

          {/* Transaction States */}
          {claimMutation.isPending && (
            <Alert>
              <Loader2 className="h-4 w-4 animate-spin" />
              <AlertDescription className="ml-2">
                {currentStep || 'Processing transaction...'}
              </AlertDescription>
            </Alert>
          )}

          {claimMutation.isSuccess && transactionHash && (
            <Alert className="border-green-500 bg-green-50 dark:bg-green-950">
              <CheckCircle className="h-4 w-4 text-green-600" />
              <AlertDescription className="ml-2">
                <div className="space-y-2">
                  <p className="text-green-900 dark:text-green-100 font-medium">
                    Reputation claimed successfully!
                  </p>
                  <a
                    href={`https://sepolia.etherscan.io/tx/${transactionHash}`}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="inline-flex items-center gap-1 text-sm text-blue-600 hover:text-blue-700 dark:text-blue-400"
                  >
                    View on Etherscan <ExternalLink className="h-3 w-3" />
                  </a>
                </div>
              </AlertDescription>
            </Alert>
          )}

          {claimMutation.isError && (
            <Alert variant="destructive">
              <AlertCircle className="h-4 w-4" />
              <AlertDescription className="ml-2">
                {claimMutation.error instanceof Error
                  ? claimMutation.error.message
                  : 'Failed to claim reputation. Please try again.'}
              </AlertDescription>
            </Alert>
          )}

          {!hasReputation && (
            <Alert>
              <AlertCircle className="h-4 w-4" />
              <AlertDescription>
                You don't have any reputation available to claim yet.
              </AlertDescription>
            </Alert>
          )}
        </div>

        <DialogFooter>
          <Button
            variant="outline"
            onClick={handleClose}
            disabled={claimMutation.isPending}
          >
            {claimMutation.isSuccess ? 'Close' : 'Cancel'}
          </Button>
          <Button
            onClick={handleClaim}
            disabled={!hasReputation || claimMutation.isPending || claimMutation.isSuccess}
          >
            {claimMutation.isPending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
            {claimMutation.isSuccess ? 'Claimed' : 'Claim Reputation'}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}
```

