Create apps/frontend/hooks/useOnChainReputation.ts to fetch on-chain reputation balance from W3Governance contract:

```typescript
'use client';

import { useQuery } from '@tanstack/react-query';
import { ethers } from 'ethers';
import { GOVERNANCE_ABI, GOVERNANCE_CONTRACT_ADDRESS } from 'common/governance-contract';

export interface OnChainReputationData {
  balanceWei: string; // Reputation balance in wei
  balancePoints: string; // Human-readable points (ethers.formatEther)
  availableToClaimWei: string; // Unclaimed reputation from backend
  canCreateProposal: boolean; // balancePoints >= MIN_REP_FOR_PROPOSAL
  canVote: boolean; // balancePoints >= MIN_REP_FOR_VOTE
}

async function fetchOnChainReputation(userAddress: string): Promise<OnChainReputationData> {
  if (!window.ethereum) {
    throw new Error('MetaMask not installed');
  }

  const provider = new ethers.BrowserProvider(window.ethereum);
  const contract = new ethers.Contract(
    GOVERNANCE_CONTRACT_ADDRESS,
    GOVERNANCE_ABI,
    provider
  );

  // Fetch on-chain balance
  const balanceWei = await contract.reputationBalances(userAddress);
  const balancePoints = parseFloat(ethers.formatEther(balanceWei));

  // Fetch available to claim from backend API
  const response = await fetch('/api/community/reputation/claimable', {
    credentials: 'include'
  });
  const claimData = await response.json();
  const availableToClaimWei = claimData.success ? claimData.data.availableWei : '0';

  // Check thresholds (match ReputationGuard constants)
  const MIN_REP_FOR_PROPOSAL = 200;
  const MIN_REP_FOR_VOTE = 50;

  return {
    balanceWei: balanceWei.toString(),
    balancePoints: balancePoints.toString(),
    availableToClaimWei,
    canCreateProposal: balancePoints >= MIN_REP_FOR_PROPOSAL,
    canVote: balancePoints >= MIN_REP_FOR_VOTE
  };
}

export function useOnChainReputation(userAddress?: string) {
  return useQuery({
    queryKey: ['onChainReputation', userAddress],
    queryFn: () => {
      if (!userAddress) throw new Error('No user address provided');
      return fetchOnChainReputation(userAddress);
    },
    enabled: !!userAddress,
    staleTime: 1000 * 60 * 2, // 2 minutes
    gcTime: 1000 * 60 * 5, // 5 minutes
    retry: 2
  });
}
```

