    REPUTATION_ABI,
    testWallet
  );

  // First claim should succeed
  const tx1 = await reputationContract.claimReputation(claimAmount, nonce, expiry, signature);
  await waitForTransaction(tx1.hash, provider);

  // Second claim with same nonce should revert
  await expect(
    reputationContract.claimReputation(claimAmount, nonce, expiry, signature)
  ).rejects.toThrow(/NonceAlreadyUsed/); // Assumes contract uses custom error like UserTransactions.sol:54
});
```

